		if (value === PDFName.of("Off")) return void 0;
		const exportValues = this.acroField.getExportValues();
		if (exportValues) {
			const onValues = this.acroField.getOnValues();
			for (let idx = 0, len = onValues.length; idx < len; idx++) if (onValues[idx] === value) return exportValues[idx].decodeText();
		}
